    @Override
    @InitializeAdmin
    @Transactional
    public void deleteRekenhoofden(Admin admin, List<Integer> rekenHoofdIds) {
        //LPBUNI-11556, LPBUNI-11571
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.fetch("opdracht{persoon}, rekenLijnen, rekenOverdrachten");
        cb.and("id", Criterium.IN(rekenHoofdIds));
        List<RekenHoofd> rekenHoofden = rekenResultatenService.findByCriteria(admin, cb);

        // LPBUNI-9321 controleer manuele tussenkomsten.
        for (RekenHoofd rekenHoofd : rekenHoofden) {
            List<ManueleTussenkomst> manueleTussenkomsten = manueleTussenkomstService
                    .findByOpdrachtenPeriode(admin, Collections.singletonList(rekenHoofd.getOpdracht()),
                            new LocalDateInterval(rekenHoofd.getBeginDatum(), rekenHoofd.getEindDatum()));

            for (ManueleTussenkomst mantus : manueleTussenkomsten) {
                if (mantus.getBron().compareTo(ManueleTussenkomstBron.NEUTRALISATIE) != 0) {
                    throw new MessageException("Contacteer Cipal Schaubroeck voor manuele tussenkomst");
                }
            }
        }

        List<RegulAgenda> regulAgendas = new ArrayList<>();
        List<RekenHoofd> anummers = new ArrayList<>();
        for (RekenHoofd rekenHoofd : rekenHoofden) {
            RegulAgenda regulAgenda = maakRegulAgenda(rekenHoofd, Regulkode.MANUEEL_VERNIETIGDE_REKENRSLT);
            regulAgendas.add(regulAgenda);
            if (rekenHoofd.getRnummer() == null) {
                rekenResultatenService.delete(admin, rekenHoofd);
            } else {
                anummers.add(rekenHoofd);
            }
        }
        artikelHoofdService.deleteVoorRekenHoofden(admin, anummers);
        deleteMaandtotalenByRekenhoofden(admin, rekenHoofden);
        regulAgendaService.create(admin, regulAgendas);
    }

