            maandTotaalService
                    .deleteZonderSnummer(admin, rekenHoofd.getOpdracht().getPersoon().getId(), rekenHoofd.getOpdracht().getOpdrachtnr(), periode, null);
        }
    }

    private RegulAgenda maakRegulAgenda(RekenHoofd rekenHoofd, Regulkode regulKode) {
        Persoon persoon = new PersoonPO(rekenHoofd.getOpdracht().getPersoon().getId());
        RegulAgenda regul = new RegulAgendaPO();
        RegulAgendaPK id = new RegulAgendaPK();
        regul.setId(id);
        regul.setBeginDatum(rekenHoofd.getBeginDatum());
        regul.setEindDatum(rekenHoofd.getEindDatum());
        regul.setWerkgever(rekenHoofd.getOpdracht().getWerkgever());
        regul.setPersoon(persoon);
        regul.setOpdrachtNummer(rekenHoofd.getOpdracht().getOpdrachtnr());
        regul.setRegulStatus(regulKode.getCode());
        regul.setBron(BronAgenda.RM_INPUT);
        return regul;
    }

