    @Override
    public List<RegulAgenda> findRegulAgendas(Werkgever werkgever) {

        TemporalContext.getInstance().setActualInterval(new Eternity());
        try {
            CriteriaBuilder cb = new CriteriaBuilder();
            cb.fetch(FETCH_WERKGEVER);
            cb.and("werkgever", Criterium.EQ(werkgever));
            List<RegulAgenda> lijst = regulAgendaService.findByCriteria(werkgever.getAdmin(), cb);
            Set<Integer> persoonids = lijst.stream().map(x -> x.getPersoon().getId()).collect(Collectors.toSet());
            CriteriaBuilder cb2 = new CriteriaBuilder();
            cb2.and("id", Criterium.IN(persoonids));
            cb2.fetch(FETCH_PERSOON_OPDRACHTEN2);
            List<Persoon> personen = persoonService.findByCriteria(werkgever.getAdmin(), cb2);
            Map<Integer, Persoon> persoonMap = personen.stream().collect(Collectors.toMap(Persoon::getId, x -> x));
            lijst.forEach(x -> x.setPersoon(persoonMap.get(x.getPersoon().getId())));
            return lijst;
        } finally {
            TemporalContext.getInstance().clearActualInterval();
        }
    }

