    private void checkRekenAgenda(
            Werkgever werkgever, LocalDateInterval periode, Persoon persoon, Integer opdrachtNr, LocalDate rekenDatum,
            LocalDate beslagDatum, LocalDate boekDatum) {
        // LPBUNI-12172: bij overdragen naar rekenagenda splitsen per jaar
        List<LocalDateInterval> perioden = LocalDateUtil.getInstance().splitPeriodenOpJaar(periode);

        for (LocalDateInterval periodeX : perioden) {
            RekenAgenda exists = getRekenAgenda(werkgever, persoon, opdrachtNr, periodeX);

            if (exists == null) {
                initRekenAgenda(werkgever, periodeX, persoon, opdrachtNr, rekenDatum, beslagDatum, boekDatum);
            }
        }
    }

    private void initRekenAgenda(
            Werkgever werkgever, LocalDateInterval periode, Persoon persoon, Integer opdrachtNr, LocalDate rekenDatum,
            LocalDate beslagDatum, LocalDate boekDatum) {
        RekenAgenda pojo = new RekenAgendaPO();
        pojo.setBeginDatum(periode.getStart());
        pojo.setEindDatum(periode.getEnd());
        pojo.setPersoon(persoon);
        pojo.setOpdrachtNummer(opdrachtNr);
        pojo.setWerkgever(werkgever);
        pojo.setRekenDatum(rekenDatum);
        pojo.setBeslagDatum(beslagDatum);
        pojo.setBoekDatum(boekDatum);
        createRekenAgenda(werkgever, pojo);
    }

