    public Long rekenRekenAgenda(Admin admin, Werkgever werkgever, String rModus, String actor) {

        List<RekenAgenda> rekenAgendas = findRekenAgendas(werkgever);
        if (rekenAgendas.isEmpty()) {
            throw new MessageException("Er zijn geen agenda's om te rekenen.");
        }

        // maximaal één proces tegelijk (per administratie)
        List<RekenProces> processen = getProcessen(admin);
        for (RekenProces proces : processen) {
            if (!(proces.isFinished() || proces.getStopFlag())) {
                throw new MessageException("Maximaal één proces tegelijk, er is al een proces bezig met rekenen.");
            }
        }

        StringBuilder omschijving = new StringBuilder();

        for (RekenAgenda rekenAgenda : rekenAgendas) {
            String beginDatumStr = LocalDateUtils.toNormalString(rekenAgenda.getBeginDatum());
            String eindDatumStr = LocalDateUtils.toNormalString(rekenAgenda.getEindDatum());
            omschijving.append(beginDatumStr).append("-").append(eindDatumStr).append(" ").append(getRekenAgendaLabel(rekenAgenda)).append(";");
        }

        Rekenmodus modus = Rekenmodus.NORMAAL;
        if ("voorschot".equals(rModus)) {
            modus = Rekenmodus.VOORSCHOT;
        } else if ("vormArtikels".equals(rModus)) {
            modus = Rekenmodus.VORM_ARTIKELS;
        } else if ("sociaalRekenen".equals(rModus)) {
            modus = Rekenmodus.SOCIAAL_REKENEN;
        } else if ("bijsturenEurocent".equals(rModus)) {
            modus = Rekenmodus.BIJSTUREN_EUROCENT;
        } else if ("neutraalRekenen".equals(rModus)) {
            modus = Rekenmodus.NEUTRAAL_REKENEN;
        } else if ("vermijdenFiche25".equals(rModus)) {
            modus = Rekenmodus.VERMIJDEN_FICHE_25;
        } else if ("nettoFiscaalVorigJaar".equals(rModus)) {
            modus = Rekenmodus.NETTO_FISCAAL_VORIG_JAAR;
        }

        if (lockLogService.rekenenBezig(admin, actor)) {
            throw new MessageException("Rekenen geblokkeerd door locks.");
        }

        return rekenProcesCentral.startProces(werkgever, modus, omschijving.toString(), actor);

    }

    private String getRekenAgendaLabel(RekenAgenda pojo) {
        String label;

        Rekengroep rekengroep = pojo.getRekenGroep();
        Hoedanigheid hoedanigheid = pojo.getHoedanigheid();
        Persoon persoon = pojo.getPersoon();

        if (persoon != null && pojo.getOpdrachtNummer() != null) {
            label = persoon.getPersoneelsNr() + "-" + pojo.getOpdrachtNummer() + " " + persoon.getFamilienaam() + " " + persoon.getVoornaam();
            if (hoedanigheid != null) {
                label += " " + hoedanigheid.getCode() + "-" + hoedanigheid.getLangeTekst();
            }
        } else if (rekengroep != null) {
            label = rekengroep.getCode() + "-" + rekengroep.getLangeTekst();
        } else if (hoedanigheid != null) {
            label = hoedanigheid.getCode() + "-" + hoedanigheid.getLangeTekst();
        } else {
            label = "Alles";
        }

        return label;
    }

