    @Override
    @InitializeAdmin
    public Long herrekenViaBoekDatum(Admin admin, Integer rnummer, LocalDate boekDatum) {
        List<ArtikelHoofd> artikelHoofden;
        List<RekenHoofd> rekenHoofden;
        Map<RekenAtoom, RekenAtoom> rekenAtomenOldMap = new HashMap<>();
        SetMultimap<RekenAtoom, Integer> atomenOldToOpdrachtNrMap = TreeMultimap.create();
        int boekjaar;
        SetMultimap<RekenAtoom, Integer> rekenAtomenMap;
        if (rnummer != null && boekDatum != null) {
            rekenHoofden = rekenHoofdService.findByRnummer(admin, rnummer);
            rekenAtomenMap = bepaalRekenAtomenMetRekenHoofden(rekenHoofden, boekDatum, rekenAtomenOldMap, atomenOldToOpdrachtNrMap);
            if (rekenHoofden.isEmpty()) {
                throw new MessageException("Geen rekenhoofden gevonden!");
            }
            artikelHoofden = rekenHoofden.stream()
                    .flatMap(rekenHoofd -> rekenHoofd.getArtikelHoofden().stream()).collect(Collectors.toList());
            if (artikelHoofden.stream().anyMatch(ah -> ah.getSnummer() != null && !ah.getSnummer().equals(rnummer))) {
                throw new MessageException("Artikelhoofden mogen geen A-nummers bevatten!");
            }
            TimeTools timeTools = new TimeTools(admin, constantService);
            RekenTijd rekenTijd = rekenAtomenMap.keySet().iterator().next().getRekenTijd();
            if (artikelHoofden.isEmpty()) {
                controleerArtikelAchterstallen(admin, rekenHoofden, boekDatum, rekenTijd);
            } else {
                controleerArtikelAchterstallen(admin, artikelHoofden.stream()
                        .map(ArtikelHoofd::getRekenHoofd).collect(Collectors.toList()), boekDatum, rekenTijd);
            }
            boekjaar = timeTools.bepaalBoekJaar(rekenTijd);
            if (boekjaar < rekenTijd.beginDatum.getYear()) {
                throw new MessageException(
                        "Deze handeling is onmogelijk aangezien uw gekozen boekjaar kleiner is " +
                                "dan het fysisch jaar van de berekening. Er zal dan ook niets gebeuren.");
            }
            if (!rekenAtomenMap.keySet().stream().allMatch(rekenAtoom -> timeTools.bepaalBoekJaar(rekenAtoom.getRekenTijd()) == boekjaar)) {
                throw new MessageException("Meerdere boekjaren voor één R-nummer is niet toegelaten.");
            }
        } else {
            throw new MessageException("RekenViaBoekDatumService.run onvoldoende parameters");
        }

        UsernamePasswordCredentials userAttribute = ExecutionContext.getContext().getUserAttribute(ExecutionContextConstants.ACTOR);
        return rekenProcesCentral.startHerrekenViaBoekDatumProces(admin, rnummer, boekDatum, boekjaar, rekenAtomenMap, atomenOldToOpdrachtNrMap, rekenAtomenOldMap,
                artikelHoofden, rekenHoofden,
                "Herreken via boekdatum met R-nummer " + rnummer + " en boekdatum " + boekDatum.toString(DateTimeFormat.forPattern("dd/MM/yyyy")),
                userAttribute.getName());
    }

    private void controleerArtikelAchterstallen(
            Admin admin, List<RekenHoofd> rekenHoofden, LocalDate boekDatum, RekenTijd rekenTijd) {
        Set<Opdracht> ontbrekendeOpdrachten = new HashSet<>();
        List<Opdracht> opdrachten = rekenHoofden.stream().map(RekenHoofd::getOpdracht).collect(Collectors.toList());
        for (Opdracht opdracht : opdrachten) {
            LocalDate aangepasteBoekDatum;
            TimeTools timeTools = new TimeTools(admin, constantService);
            if (timeTools.getIsBoekAchterstalTester(rekenTijd).test(boekDatum)) {
                aangepasteBoekDatum = boekDatum.withDayOfMonth(1);
            } else {
                aangepasteBoekDatum = rekenTijd.beginDatum.withDayOfMonth(1);
            }
            if (opdracht.getBeginDatum().isAfter(aangepasteBoekDatum) ||
                    opdracht.getEindDatum().isBefore(aangepasteBoekDatum)) {
                //opdracht artikel achterstal nodig
                CriteriaBuilder cb = new CriteriaBuilder();
                cb.fetch("artikelAchterstallen");
                cb.and("opdracht.id", EQ(opdracht.getId()));
                cb.and("opdrachtAchterstalPeriode.begindatum", LE(boekDatum));
                cb.and("opdrachtAchterstalPeriode.einddatum", GT(boekDatum));
                List<OpdrachtAchterstal> opdrachtAchterstallen = opdrachtAchterstalService.findByCriteria(admin, cb);
                for (OpdrachtAchterstal opdrachtAchterstal : opdrachtAchterstallen) {
                    if (opdrachtAchterstal.getArtikelAchterstallen().isEmpty()) {
                        ontbrekendeOpdrachten.add(opdracht);
                    }
                }
            }
        }
        if (!ontbrekendeOpdrachten.isEmpty()) {
            throw new MessageException(maakOpdrachtFoutmelding(ontbrekendeOpdrachten));
        }
    }

    private String maakOpdrachtFoutmelding(Set<Opdracht> ontbrekendeOpdrachten) {
        StringBuilder opdrachtenFoutmelding = new StringBuilder();
        opdrachtenFoutmelding.append("Volgende opdrachten bevatten geen opdrachtartikel achterstal: ");
        opdrachtenFoutmelding.append(System.getProperty("line.separator"));
        for (Opdracht ontbrekendeOpdracht : ontbrekendeOpdrachten) {
            opdrachtenFoutmelding.append("Personeelsnr: ")
                    .append(ontbrekendeOpdracht.getPersoon().getPersoneelsNr())
                    .append(", opdrachtnr: ")
                    .append(ontbrekendeOpdracht.getOpdrachtnr())
                    .append(", naam: ")
                    .append(ontbrekendeOpdracht.getPersoon().getFamilienaam())
                    .append(", voornaam: ")
                    .append(ontbrekendeOpdracht.getPersoon().getVoornaam())
                    .append(System.getProperty("line.separator"));
        }
        return opdrachtenFoutmelding.toString();
    }

    private SetMultimap<RekenAtoom, Integer> bepaalRekenAtomenMetRekenHoofden(
            List<RekenHoofd> rekenHoofden, LocalDate boekDatum,
            Map<RekenAtoom, RekenAtoom> rekenAtomenOldMap,
            SetMultimap<RekenAtoom, Integer> atomenOldToOpdrachtNrMap) {
        LocalDateTime rekenTijdstip = TemporalContext.getInstance().getWerkTijdstip();
        LocalDate rekenDatum = rekenTijdstip.toLocalDate();
        SetMultimap<RekenAtoom, Integer> atomenToOpdrachtNrMap = TreeMultimap.create();
        for (RekenHoofd rekenHoofd : rekenHoofden) {
            if (rekenHoofd.getArtikelHoofden().isEmpty()) {
                atomenToOpdrachtNrMap.putAll(
                        bepaalRekenAtomenMetRekenHoofden(rekenHoofd, boekDatum, rekenDatum, rekenTijdstip, rekenAtomenOldMap, atomenOldToOpdrachtNrMap));
            } else {
                atomenToOpdrachtNrMap.putAll(
                        bepaalRekenAtomenMetArtikelHoofden(Lists.newArrayList(rekenHoofd.getArtikelHoofden()), boekDatum, rekenAtomenOldMap, atomenOldToOpdrachtNrMap));
            }
        }
        return atomenToOpdrachtNrMap;
    }

    private SetMultimap<RekenAtoom, Integer> bepaalRekenAtomenMetRekenHoofden(
            RekenHoofd rekenHoofd, LocalDate boekDatum, LocalDate rekenDatum, LocalDateTime rekenTijdstip,
            Map<RekenAtoom, RekenAtoom> rekenAtomenOldMap,
            SetMultimap<RekenAtoom, Integer> atomenOldToOpdrachtNrMap) {
        SetMultimap<RekenAtoom, Integer> atomenToOpdrachtNrMap = TreeMultimap.create();
        LocalDate beginDatum = rekenHoofd.getBeginDatum().dayOfMonth().withMinimumValue();
        LocalDateInterval rekenPeriode = new Month(beginDatum);
        RekenTijd rekenTijd = new RekenTijd(rekenPeriode, rekenDatum, boekDatum, rekenDatum, rekenTijdstip);
        RekenAtoom atoom = new RekenAtoom(rekenTijd, rekenHoofd.getOpdracht().getPersoon().getId());
        RekenTijd rekenTijdOld = new RekenTijd(rekenPeriode, rekenDatum, rekenHoofd.getRekenDatum(), rekenDatum, rekenTijdstip);
        RekenAtoom atoomOld = new RekenAtoom(rekenTijdOld, rekenHoofd.getOpdracht().getPersoon().getId());
        atomenToOpdrachtNrMap.put(atoom, rekenHoofd.getOpdracht().getOpdrachtnr());
        atomenOldToOpdrachtNrMap.put(atoomOld, rekenHoofd.getOpdracht().getOpdrachtnr());
        rekenAtomenOldMap.put(atoom, atoomOld);
        return atomenToOpdrachtNrMap;
    }

    private SetMultimap<RekenAtoom, Integer> bepaalRekenAtomenMetArtikelHoofden(
            List<ArtikelHoofd> artikelHoofden, LocalDate boekDatum,
            Map<RekenAtoom, RekenAtoom> rekenAtomenOldMap,
            SetMultimap<RekenAtoom, Integer> atomenOldToOpdrachtNrMap) {
        LocalDateTime rekenTijdstip = TemporalContext.getInstance().getWerkTijdstip();
        LocalDate rekenDatum = rekenTijdstip.toLocalDate();
        SetMultimap<RekenAtoom, Integer> atomenToOpdrachtNrMap = TreeMultimap.create();
        artikelHoofden.forEach(artikelHoofd -> atomenToOpdrachtNrMap.putAll(
                bepaalRekenAtomenMetArtikelHoofden(artikelHoofd, boekDatum, rekenDatum, rekenTijdstip, rekenAtomenOldMap, atomenOldToOpdrachtNrMap)));
        return atomenToOpdrachtNrMap;
    }

    private SetMultimap<RekenAtoom, Integer> bepaalRekenAtomenMetArtikelHoofden(
            ArtikelHoofd artikelHoofd, LocalDate boekDatum, LocalDate rekenDatum, LocalDateTime rekenTijdstip,
            Map<RekenAtoom, RekenAtoom> rekenAtomenOldMap,
            SetMultimap<RekenAtoom, Integer> atomenOldToOpdrachtNrMap) {
