        RekenTijd rekenTijd = new RekenTijd(rekenPeriode, rekenDatum, boekDatum, rekenDatum, rekenTijdstip);
        RekenAtoom atoom = new RekenAtoom(rekenTijd, artikelHoofd.getRekenHoofd().getOpdracht().getPersoon().getId());
        RekenTijd rekenTijdOld = new RekenTijd(rekenPeriode, rekenDatum, artikelHoofd.getBoekDatum(), rekenDatum, rekenTijdstip);
        RekenAtoom atoomOld = new RekenAtoom(rekenTijdOld, artikelHoofd.getRekenHoofd().getOpdracht().getPersoon().getId());
        atomenToOpdrachtNrMap.put(atoom, artikelHoofd.getRekenHoofd().getOpdracht().getOpdrachtnr());
        atomenOldToOpdrachtNrMap.put(atoomOld, artikelHoofd.getRekenHoofd().getOpdracht().getOpdrachtnr());
